contracts/CompanyRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";

/**
 * @title CompanyRegistry
 * @dev Registry for companies participating in the payroll system
 * Handles company registration, KYC verification, and status management
 */
contract CompanyRegistry is Ownable, ReentrancyGuard {
    using EnumerableSet for EnumerableSet.AddressSet;

    // Company status
    enum CompanyStatus {
        Pending,        // Registration pending KYC verification
        Active,         // Active and verified
        Suspended,      // Suspended due to violations
        Inactive       // Deactivated by company
    }

    // Company structure
    struct Company {
        address companyAddress;
        string name;
        string legalId;        // Legal business ID/tax ID
        string country;
        string industry;
        uint256 registeredAt;
        uint256 verifiedAt;
        CompanyStatus status;
        uint256 totalWorkers;  // Number of registered workers
        uint256 totalPaid;     // Total USDC paid to workers
    }

    // State variables
    mapping(address => Company) public companies;
    EnumerableSet.AddressSet private companyAddresses;

    // KYC verification authority (can be updated by owner)
    address public kycVerifier;

    // Events
    event CompanyRegistered(
        address indexed companyAddress,
        string name,
        uint256 timestamp
    );

    event CompanyVerified(
        address indexed companyAddress,
        uint256 timestamp
    );

    event CompanyStatusChanged(
        address indexed companyAddress,
        CompanyStatus oldStatus,
        CompanyStatus newStatus,
        uint256 timestamp
    );

    event CompanyUpdated(
        address indexed companyAddress,
        string name,
        string country,
        string industry,
        uint256 timestamp
    );

    event WorkerCountUpdated(
        address indexed companyAddress,
        uint256 newCount,
        uint256 timestamp
    );

    event TotalPaidUpdated(
        address indexed companyAddress,
        uint256 amount,
        uint256 timestamp
    );

    event KYCVerifierChanged(
        address indexed oldVerifier,
        address indexed newVerifier,
        uint256 timestamp
    );

    // Errors
    error CompanyAlreadyRegistered();
    error CompanyNotFound();
    error InvalidAddress();
    error NotAuthorized();
    error InvalidStatus();
    error NotKYCVerifier();
    error EmptyString();

    /**
     * @dev Constructor
     * @param _initialOwner Initial owner of the contract
     * @param _kycVerifier Initial KYC verifier address
     */
    constructor(address _initialOwner, address _kycVerifier) Ownable(_initialOwner) {
        if (_kycVerifier == address(0)) revert InvalidAddress();
        kycVerifier = _kycVerifier;
    }

    /**
     * @dev Register a new company
     * @param _name Company name
     * @param _legalId Legal business ID/tax ID
     * @param _country Country of registration
     * @param _industry Industry sector
     */
    function registerCompany(
        string memory _name,
        string memory _legalId,
        string memory _country,
        string memory _industry
    ) external nonReentrant {
        if (bytes(_name).length == 0) revert EmptyString();
        if (bytes(_legalId).length == 0) revert EmptyString();
        if (companies[msg.sender].companyAddress != address(0)) {
            revert CompanyAlreadyRegistered();
        }

        companies[msg.sender] = Company({
            companyAddress: msg.sender,
            name: _name,
            legalId: _legalId,
            country: _country,
            industry: _industry,
            registeredAt: block.timestamp,
            verifiedAt: 0,
            status: CompanyStatus.Pending,
            totalWorkers: 0,
            totalPaid: 0
        });

        companyAddresses.add(msg.sender);

        emit CompanyRegistered(msg.sender, _name, block.timestamp);
    }

    /**
     * @dev Verify a company (KYC approved)
     * @param _companyAddress Address of the company to verify
     */
    function verifyCompany(address _companyAddress) external nonReentrant {
        if (msg.sender != kycVerifier) revert NotKYCVerifier();
        if (companies[_companyAddress].companyAddress == address(0)) {
            revert CompanyNotFound();
        }

        companies[_companyAddress].status = CompanyStatus.Active;
        companies[_companyAddress].verifiedAt = block.timestamp;

        emit CompanyVerified(_companyAddress, block.timestamp);
        emit CompanyStatusChanged(
            _companyAddress,
            CompanyStatus.Pending,
            CompanyStatus.Active,
            block.timestamp
        );
    }

    /**
     * @dev Update company information
     * @param _name New company name
     * @param _country New country
     * @param _industry New industry
     */
    function updateCompanyInfo(
        string memory _name,
        string memory _country,
        string memory _industry
    ) external nonReentrant {
        if (companies[msg.sender].companyAddress == address(0)) {
            revert CompanyNotFound();
        }
        if (bytes(_name).length == 0) revert EmptyString();

        companies[msg.sender].name = _name;
        companies[msg.sender].country = _country;
        companies[msg.sender].industry = _industry;

        emit CompanyUpdated(
            msg.sender,
            _name,
            _country,
            _industry,
            block.timestamp
        );
    }

    /**
     * @dev Change company status (only owner or KYC verifier)
     * @param _companyAddress Address of the company
     * @param _newStatus New status
     */
    function changeCompanyStatus(
        address _companyAddress,
        CompanyStatus _newStatus
    ) external nonReentrant {
        if (msg.sender != owner() && msg.sender != kycVerifier) {
            revert NotAuthorized();
        }
        if (companies[_companyAddress].companyAddress == address(0)) {
            revert CompanyNotFound();
        }

        CompanyStatus oldStatus = companies[_companyAddress].status;
        companies[_companyAddress].status = _newStatus;

        emit CompanyStatusChanged(
            _companyAddress,
            oldStatus,
            _newStatus,
            block.timestamp
        );
    }

    /**
     * @dev Update worker count for a company (called by PayrollContract)
     * @param _companyAddress Address of the company
     * @param _newCount New worker count
     */
    function updateWorkerCount(address _companyAddress, uint256 _newCount) external {
        if (companies[_companyAddress].companyAddress == address(0)) {
            revert CompanyNotFound();
        }
        companies[_companyAddress].totalWorkers = _newCount;

        emit WorkerCountUpdated(_companyAddress, _newCount, block.timestamp);
    }

    /**
     * @dev Update total paid amount for a company (called by PayrollContract)
     * @param _companyAddress Address of the company
     * @param _amount Amount paid
     */
    function updateTotalPaid(address _companyAddress, uint256 _amount) external {
        if (companies[_companyAddress].companyAddress == address(0)) {
            revert CompanyNotFound();
        }
        companies[_companyAddress].totalPaid += _amount;

        emit TotalPaidUpdated(_companyAddress, _amount, block.timestamp);
    }

    /**
     * @dev Set new KYC verifier (only owner)
     * @param _newVerifier New verifier address
     */
    function setKYCVerifier(address _newVerifier) external onlyOwner {
        if (_newVerifier == address(0)) revert InvalidAddress();
        address oldVerifier = kycVerifier;
        kycVerifier = _newVerifier;

        emit KYCVerifierChanged(oldVerifier, _newVerifier, block.timestamp);
    }

    /**
     * @dev Get company details
     * @param _companyAddress Address of the company
     */
    function getCompany(address _companyAddress) external view returns (Company memory) {
        if (companies[_companyAddress].companyAddress == address(0)) {
            revert CompanyNotFound();
        }
        return companies[_companyAddress];
    }

    /**
     * @dev Check if an address is a registered company
     * @param _companyAddress Address to check
     */
    function isCompany(address _companyAddress) external view returns (bool) {
        return companies[_companyAddress].companyAddress != address(0);
    }

    /**
     * @dev Check if a company is verified (Active status)
     * @param _companyAddress Address of the company
     */
    function isVerifiedCompany(address _companyAddress) external view returns (bool) {
        return companies[_companyAddress].status == CompanyStatus.Active;
    }

    /**
     * @dev Get total number of registered companies
     */
    function getTotalCompanies() external view returns (uint256) {
        return companyAddresses.length();
    }

    /**
     * @dev Get all registered company addresses
     */
    function getAllCompanyAddresses() external view returns (address[] memory) {
        uint256 length = companyAddresses.length();
        address[] memory addresses = new address[](length);

        for (uint256 i = 0; i < length; i++) {
            addresses[i] = companyAddresses.at(i);
        }

        return addresses;
    }

    /**
     * @dev Get companies by status
     * @param _status Status to filter by
     */
    function getCompaniesByStatus(CompanyStatus _status) external view returns (address[] memory) {
        uint256 length = companyAddresses.length();
        uint256 count = 0;

        // First pass: count matching companies
        for (uint256 i = 0; i < length; i++) {
            if (companies[companyAddresses.at(i)].status == _status) {
                count++;
            }
        }

        // Second pass: collect addresses
        address[] memory addresses = new address[](count);
        uint256 index = 0;

        for (uint256 i = 0; i < length; i++) {
            if (companies[companyAddresses.at(i)].status == _status) {
                addresses[index] = companyAddresses.at(i);
                index++;
            }
        }

        return addresses;
    }

    /**
     * @dev Get paginated list of companies
     * @param _offset Starting index
     * @param _limit Number of companies to return
     */
    function getPaginatedCompanies(uint256 _offset, uint256 _limit) external view returns (Company[] memory) {
        uint256 length = companyAddresses.length();
        if (_offset >= length) {
            return new Company[](0);
        }

        uint256 end = _offset + _limit;
        if (end > length) {
            end = length;
        }

        Company[] memory companyList = new Company[](end - _offset);
        uint256 index = 0;

        for (uint256 i = _offset; i < end; i++) {
            companyList[index] = companies[companyAddresses.at(i)];
            index++;
        }

        return companyList;
    }
}

contracts/PayrollContract.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title PayrollContract
 * @dev Handles payroll payments with escrow and batch payment functionality
 * Integrates with CompanyRegistry and WorkerRegistry for verification
 */
contract PayrollContract is Ownable, ReentrancyGuard {
    IERC20 public usdcToken;
    address public companyRegistry;
    address public workerRegistry;

    struct Payment {
        uint256 id;
        address worker;
        uint256 amount;
        uint256 timestamp;
        bool isReleased;
        bool isEscrowed;
        address employer;
        uint256 escrowReleaseTime;
    }

    mapping(uint256 => Payment) public payments;

    uint256 public paymentCounter;
    uint256 public defaultEscrowTime = 7 days; // 7 days default escrow period

    // Events
    event PaymentCreated(uint256 indexed paymentId, address indexed worker, uint256 amount, bool useEscrow);
    event PaymentReleased(uint256 indexed paymentId, address indexed worker, uint256 amount);
    event PaymentEscrowed(uint256 indexed paymentId, uint256 releaseTime);
    event BatchPaymentCreated(uint256[] paymentIds, address indexed employer, uint256 totalAmount);
    event CompanyRegistryUpdated(address indexed oldRegistry, address indexed newRegistry);
    event WorkerRegistryUpdated(address indexed oldRegistry, address indexed newRegistry);
    event EscrowTimeUpdated(uint256 oldTime, uint256 newTime);
    event EmergencyWithdraw(address indexed to, uint256 amount);

    // Errors
    error InvalidAddress();
    error NotAuthorized();
    error WorkerNotVerified();
    error CompanyNotVerified();
    error AmountZero();
    error PaymentNotFound();
    error PaymentAlreadyReleased();
    error EscrowNotOver();
    error ArraysLengthMismatch();
    error TransferFailed();
    error RegistryNotSet();

    /**
     * @dev Constructor
     * @param _usdcToken USDC token address
     * @param _companyRegistry Company registry contract address
     * @param _workerRegistry Worker registry contract address
     */
    constructor(
        address _usdcToken,
        address _companyRegistry,
        address _workerRegistry
    ) Ownable(msg.sender) {
        if (_usdcToken == address(0)) revert InvalidAddress();
        usdcToken = IERC20(_usdcToken);
        companyRegistry = _companyRegistry;
        workerRegistry = _workerRegistry;
    }

    /**
     * @dev Modifier to check if sender is a verified company
     */
    modifier onlyVerifiedCompany() {
        if (companyRegistry != address(0)) {
            (bool success, bytes memory data) = companyRegistry.staticcall(
                abi.encodeWithSignature("isVerifiedCompany(address)", msg.sender)
            );
            if (success && data.length > 0) {
                bool isVerified = abi.decode(data, (bool));
                if (!isVerified) revert NotAuthorized();
            } else {
                revert NotAuthorized();
            }
        } else {
            revert NotAuthorized();
        }
        _;
    }

    /**
     * @dev Modifier to check if worker is verified
     */
    modifier onlyVerifiedWorker(address _worker) {
        if (workerRegistry != address(0)) {
            (bool success, bytes memory data) = workerRegistry.staticcall(
                abi.encodeWithSignature("isVerifiedWorker(address)", _worker)
            );
            if (success && data.length > 0) {
                bool isVerified = abi.decode(data, (bool));
                if (!isVerified) revert WorkerNotVerified();
            } else {
                revert WorkerNotVerified();
            }
        } else {
            revert WorkerNotVerified();
        }
        _;
    }

    /**
     * @dev Set company registry address (only owner)
     * @param _companyRegistry New company registry address
     */
    function setCompanyRegistry(address _companyRegistry) external onlyOwner {
        if (_companyRegistry == address(0)) revert InvalidAddress();
        address oldRegistry = companyRegistry;
        companyRegistry = _companyRegistry;
        emit CompanyRegistryUpdated(oldRegistry, _companyRegistry);
    }

    /**
     * @dev Set worker registry address (only owner)
     * @param _workerRegistry New worker registry address
     */
    function setWorkerRegistry(address _workerRegistry) external onlyOwner {
        if (_workerRegistry == address(0)) revert InvalidAddress();
        address oldRegistry = workerRegistry;
        workerRegistry = _workerRegistry;
        emit WorkerRegistryUpdated(oldRegistry, _workerRegistry);
    }

    /**
     * @dev Set default escrow time (only owner)
     * @param _escrowTime New escrow time in seconds
     */
    function setEscrowTime(uint256 _escrowTime) external onlyOwner {
        uint256 oldTime = defaultEscrowTime;
        defaultEscrowTime = _escrowTime;
        emit EscrowTimeUpdated(oldTime, _escrowTime);
    }

    /**
     * @dev Create a single payment
     * @param _worker Worker address
     * @param _amount Amount in USDC (6 decimals)
     * @param _useEscrow Whether to use escrow
     * @param _customEscrowTime Custom escrow time (0 = use default)
     */
    function createPayment(
        address _worker,
        uint256 _amount,
        bool _useEscrow,
        uint256 _customEscrowTime
    ) external onlyVerifiedCompany nonReentrant returns (uint256) {
        if (_amount == 0) revert AmountZero();
        if (workerRegistry == address(0)) revert RegistryNotSet();

        // Verify worker exists
        (bool success, bytes memory data) = workerRegistry.staticcall(
            abi.encodeWithSignature("isWorker(address)", _worker)
        );
        if (!success || data.length == 0 || !abi.decode(data, (bool))) {
            revert WorkerNotVerified();
        }

        // Transfer USDC from employer to contract
        bool transferSuccess = usdcToken.transferFrom(msg.sender, address(this), _amount);
        if (!transferSuccess) revert TransferFailed();

        paymentCounter++;
        uint256 escrowReleaseTime = _useEscrow 
            ? (_customEscrowTime > 0 ? _customEscrowTime : block.timestamp + defaultEscrowTime)
            : 0;

        payments[paymentCounter] = Payment({
            id: paymentCounter,
            worker: _worker,
            amount: _amount,
            timestamp: block.timestamp,
            isReleased: false,
            isEscrowed: _useEscrow,
            employer: msg.sender,
            escrowReleaseTime: escrowReleaseTime
        });

        if (_useEscrow) {
            emit PaymentEscrowed(paymentCounter, escrowReleaseTime);
        }

        emit PaymentCreated(paymentCounter, _worker, _amount, _useEscrow);
        return paymentCounter;
    }

    /**
     * @dev Create batch payments
     * @param _workers Array of worker addresses
     * @param _amounts Array of amounts (must match workers array length)
     * @param _useEscrow Whether to use escrow for all payments
     */
    function batchCreatePayments(
        address[] calldata _workers,
        uint256[] calldata _amounts,
        bool _useEscrow
    ) external onlyVerifiedCompany nonReentrant returns (uint256[] memory) {
        if (_workers.length != _amounts.length) revert ArraysLengthMismatch();
        if (_workers.length == 0) revert AmountZero();
        if (workerRegistry == address(0)) revert RegistryNotSet();

        uint256 totalAmount = 0;
        for (uint256 i = 0; i < _amounts.length; i++) {
            if (_amounts[i] == 0) revert AmountZero();
            totalAmount += _amounts[i];
        }

        // Transfer USDC from employer to contract
        bool transferSuccess = usdcToken.transferFrom(msg.sender, address(this), totalAmount);
        if (!transferSuccess) revert TransferFailed();

        uint256[] memory paymentIds = new uint256[](_workers.length);
        uint256 escrowReleaseTime = _useEscrow ? block.timestamp + defaultEscrowTime : 0;

        for (uint256 i = 0; i < _workers.length; i++) {
            // Verify worker exists
            (bool success, bytes memory data) = workerRegistry.staticcall(
                abi.encodeWithSignature("isWorker(address)", _workers[i])
            );
            if (!success || data.length == 0 || !abi.decode(data, (bool))) {
                revert WorkerNotVerified();
            }

            paymentCounter++;
            payments[paymentCounter] = Payment({
                id: paymentCounter,
                worker: _workers[i],
                amount: _amounts[i],
                timestamp: block.timestamp,
                isReleased: false,
                isEscrowed: _useEscrow,
                employer: msg.sender,
                escrowReleaseTime: escrowReleaseTime
            });

            paymentIds[i] = paymentCounter;
            emit PaymentCreated(paymentCounter, _workers[i], _amounts[i], _useEscrow);

            if (_useEscrow) {
                emit PaymentEscrowed(paymentCounter, escrowReleaseTime);
            }
        }

        emit BatchPaymentCreated(paymentIds, msg.sender, totalAmount);
        return paymentIds;
    }

    /**
     * @dev Release payment to worker
     * @param _paymentId Payment ID to release
     */
    function releasePayment(uint256 _paymentId) external nonReentrant {
        Payment storage payment = payments[_paymentId];
        if (payment.id == 0) revert PaymentNotFound();
        if (payment.isReleased) revert PaymentAlreadyReleased();

        if (payment.isEscrowed) {
            // Check if worker is KYC verified
            (bool success, bytes memory data) = workerRegistry.staticcall(
                abi.encodeWithSignature("isVerifiedWorker(address)", payment.worker)
            );
            if (!success || data.length == 0 || !abi.decode(data, (bool))) {
                revert WorkerNotVerified();
            }

            // Check escrow period
            if (block.timestamp < payment.escrowReleaseTime) {
                revert EscrowNotOver();
            }
        }

        payment.isReleased = true;

        // Update worker's total earned in registry
        if (workerRegistry != address(0)) {
            (bool registrySuccess, ) = workerRegistry.call(
                abi.encodeWithSignature("updateTotalEarned(address,uint256)", payment.worker, payment.amount)
            );
            // Don't revert if registry call fails, just log
        }

        // Update employer's total paid in registry
        if (companyRegistry != address(0)) {
            (bool registrySuccess, ) = companyRegistry.call(
                abi.encodeWithSignature("updateTotalPaid(address,uint256)", payment.employer, payment.amount)
            );
            // Don't revert if registry call fails, just log
        }

        bool transferSuccess = usdcToken.transfer(payment.worker, payment.amount);
        if (!transferSuccess) revert TransferFailed();

        emit PaymentReleased(_paymentId, payment.worker, payment.amount);
    }

    /**
     * @dev Get payment details
     * @param _paymentId Payment ID
     */
    function getPayment(uint256 _paymentId) external view returns (Payment memory) {
        if (payments[_paymentId].id == 0) revert PaymentNotFound();
        return payments[_paymentId];
    }

    /**
     * @dev Get all payments for a worker
     * @param _worker Worker address
     */
    function getWorkerPayments(address _worker) external view returns (uint256[] memory) {
        uint256 count = 0;
        for (uint256 i = 1; i <= paymentCounter; i++) {
            if (payments[i].worker == _worker) {
                count++;
            }
        }

        uint256[] memory workerPayments = new uint256[](count);
        uint256 index = 0;
        for (uint256 i = 1; i <= paymentCounter; i++) {
            if (payments[i].worker == _worker) {
                workerPayments[index] = i;
                index++;
            }
        }

        return workerPayments;
    }

    /**
     * @dev Get all payments for an employer
     * @param _employer Employer address
     */
    function getEmployerPayments(address _employer) external view returns (uint256[] memory) {
        uint256 count = 0;
        for (uint256 i = 1; i <= paymentCounter; i++) {
            if (payments[i].employer == _employer) {
                count++;
            }
        }

        uint256[] memory employerPayments = new uint256[](count);
        uint256 index = 0;
        for (uint256 i = 1; i <= paymentCounter; i++) {
            if (payments[i].employer == _employer) {
                employerPayments[index] = i;
                index++;
            }
        }

        return employerPayments;
    }

    /**
     * @dev Get pending payments for a worker
     * @param _worker Worker address
     */
    function getPendingPayments(address _worker) external view returns (uint256[] memory) {
        uint256 count = 0;
        for (uint256 i = 1; i <= paymentCounter; i++) {
            if (payments[i].worker == _worker && !payments[i].isReleased) {
                count++;
            }
        }

        uint256[] memory pendingPayments = new uint256[](count);
        uint256 index = 0;
        for (uint256 i = 1; i <= paymentCounter; i++) {
            if (payments[i].worker == _worker && !payments[i].isReleased) {
                pendingPayments[index] = i;
                index++;
            }
        }

        return pendingPayments;
    }

    /**
     * @dev Emergency withdraw funds (only owner)
     * @param _amount Amount to withdraw
     * @param _to Address to send funds to
     */
    function emergencyWithdraw(uint256 _amount, address _to) external onlyOwner {
        if (_to == address(0)) revert InvalidAddress();
        bool transferSuccess = usdcToken.transfer(_to, _amount);
        if (!transferSuccess) revert TransferFailed();
        emit EmergencyWithdraw(_to, _amount);
    }

    /**
     * @dev Get total contract balance
     */
    function getContractBalance() external view returns (uint256) {
        return usdcToken.balanceOf(address(this));
    }
}

contracts/WorkerRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";

/**
 * @title WorkerRegistry
 * @dev Registry for workers participating in the payroll system
 * Handles worker registration, KYC verification, and salary management
 */
contract WorkerRegistry is Ownable, ReentrancyGuard {
    using EnumerableSet for EnumerableSet.AddressSet;

    // Worker status
    enum WorkerStatus {
        Pending,        // Registration pending KYC verification
        Active,         // Active and verified
        Suspended,      // Suspended due to violations
        Inactive       // Deactivated by worker
    }

    // Worker structure
    struct Worker {
        address workerAddress;
        string name;
        string email;
        string country;
        string currency;      // Preferred payout currency (e.g., "USD", "IDR")
        uint256 registeredAt;
        uint256 verifiedAt;
        WorkerStatus status;
        address employer;     // Current employer address
        uint256 salary;       // Current salary in USDC (6 decimals)
        uint256 totalEarned;  // Total USDC earned across all jobs
    }

    // State variables
    mapping(address => Worker) public workers;
    EnumerableSet.AddressSet private workerAddresses;

    // KYC verification authority (can be updated by owner)
    address public kycVerifier;

    // Company registry address (for verification)
    address public companyRegistry;

    // Events
    event WorkerRegistered(
        address indexed workerAddress,
        string name,
        uint256 timestamp
    );

    event WorkerVerified(
        address indexed workerAddress,
        uint256 timestamp
    );

    event WorkerStatusChanged(
        address indexed workerAddress,
        WorkerStatus oldStatus,
        WorkerStatus newStatus,
        uint256 timestamp
    );

    event WorkerUpdated(
        address indexed workerAddress,
        string name,
        string email,
        string country,
        string currency,
        uint256 timestamp
    );

    event EmployerAssigned(
        address indexed workerAddress,
        address indexed employer,
        uint256 salary,
        uint256 timestamp
    );

    event SalaryUpdated(
        address indexed workerAddress,
        uint256 oldSalary,
        uint256 newSalary,
        uint256 timestamp
    );

    event TotalEarnedUpdated(
        address indexed workerAddress,
        uint256 amount,
        uint256 timestamp
    );

    event KYCVerifierChanged(
        address indexed oldVerifier,
        address indexed newVerifier,
        uint256 timestamp
    );

    event CompanyRegistryChanged(
        address indexed oldRegistry,
        address indexed newRegistry,
        uint256 timestamp
    );

    // Errors
    error WorkerAlreadyRegistered();
    error WorkerNotFound();
    error InvalidAddress();
    error NotAuthorized();
    error InvalidStatus();
    error NotKYCVerifier();
    error EmptyString();
    error NotVerifiedCompany();

    /**
     * @dev Constructor
     * @param _initialOwner Initial owner of the contract
     * @param _kycVerifier Initial KYC verifier address
     * @param _companyRegistry Company registry contract address
     */
    constructor(
        address _initialOwner,
        address _kycVerifier,
        address _companyRegistry
    ) Ownable(_initialOwner) {
        if (_kycVerifier == address(0)) revert InvalidAddress();
        kycVerifier = _kycVerifier;
        companyRegistry = _companyRegistry;
    }

    /**
     * @dev Register a new worker
     * @param _name Worker name
     * @param _email Worker email
     * @param _country Worker country
     * @param _currency Preferred payout currency
     */
    function registerWorker(
        string memory _name,
        string memory _email,
        string memory _country,
        string memory _currency
    ) external nonReentrant {
        if (bytes(_name).length == 0) revert EmptyString();
        if (bytes(_email).length == 0) revert EmptyString();
        if (workers[msg.sender].workerAddress != address(0)) {
            revert WorkerAlreadyRegistered();
        }

        workers[msg.sender] = Worker({
            workerAddress: msg.sender,
            name: _name,
            email: _email,
            country: _country,
            currency: _currency,
            registeredAt: block.timestamp,
            verifiedAt: 0,
            status: WorkerStatus.Pending,
            employer: address(0),
            salary: 0,
            totalEarned: 0
        });

        workerAddresses.add(msg.sender);

        emit WorkerRegistered(msg.sender, _name, block.timestamp);
    }

    /**
     * @dev Verify a worker (KYC approved)
     * @param _workerAddress Address of the worker to verify
     */
    function verifyWorker(address _workerAddress) external nonReentrant {
        if (msg.sender != kycVerifier) revert NotKYCVerifier();
        if (workers[_workerAddress].workerAddress == address(0)) {
            revert WorkerNotFound();
        }

        workers[_workerAddress].status = WorkerStatus.Active;
        workers[_workerAddress].verifiedAt = block.timestamp;

        emit WorkerVerified(_workerAddress, block.timestamp);
        emit WorkerStatusChanged(
            _workerAddress,
            WorkerStatus.Pending,
            WorkerStatus.Active,
            block.timestamp
        );
    }

    /**
     * @dev Update worker information
     * @param _name New name
     * @param _email New email
     * @param _country New country
     * @param _currency New currency
     */
    function updateWorkerInfo(
        string memory _name,
        string memory _email,
        string memory _country,
        string memory _currency
    ) external nonReentrant {
        if (workers[msg.sender].workerAddress == address(0)) {
            revert WorkerNotFound();
        }
        if (bytes(_name).length == 0) revert EmptyString();

        workers[msg.sender].name = _name;
        workers[msg.sender].email = _email;
        workers[msg.sender].country = _country;
        workers[msg.sender].currency = _currency;

        emit WorkerUpdated(
            msg.sender,
            _name,
            _email,
            _country,
            _currency,
            block.timestamp
        );
    }

    /**
     * @dev Assign worker to an employer (called by employer or system)
     * @param _workerAddress Address of the worker
     * @param _employer Address of the employer
     * @param _salary Salary in USDC (6 decimals)
     */
    function assignEmployer(
        address _workerAddress,
        address _employer,
        uint256 _salary
    ) external nonReentrant {
        if (workers[_workerAddress].workerAddress == address(0)) {
            revert WorkerNotFound();
        }

        // Verify employer is registered company
        if (companyRegistry != address(0)) {
            (bool success, bytes memory data) = companyRegistry.staticcall(
                abi.encodeWithSignature("isVerifiedCompany(address)", _employer)
            );
            if (success && data.length > 0) {
                bool isVerified = abi.decode(data, (bool));
                if (!isVerified) revert NotVerifiedCompany();
            }
        }

        workers[_workerAddress].employer = _employer;
        workers[_workerAddress].salary = _salary;

        emit EmployerAssigned(_workerAddress, _employer, _salary, block.timestamp);
    }

    /**
     * @dev Update worker salary
     * @param _workerAddress Address of the worker
     * @param _newSalary New salary in USDC (6 decimals)
     */
    function updateSalary(address _workerAddress, uint256 _newSalary) external nonReentrant {
        if (workers[_workerAddress].workerAddress == address(0)) {
            revert WorkerNotFound();
        }

        // Only employer or worker can update salary
        if (msg.sender != workers[_workerAddress].employer && msg.sender != _workerAddress) {
            revert NotAuthorized();
        }

        uint256 oldSalary = workers[_workerAddress].salary;
        workers[_workerAddress].salary = _newSalary;

        emit SalaryUpdated(_workerAddress, oldSalary, _newSalary, block.timestamp);
    }

    /**
     * @dev Change worker status (only owner or KYC verifier)
     * @param _workerAddress Address of the worker
     * @param _newStatus New status
     */
    function changeWorkerStatus(
        address _workerAddress,
        WorkerStatus _newStatus
    ) external nonReentrant {
        if (msg.sender != owner() && msg.sender != kycVerifier) {
            revert NotAuthorized();
        }
        if (workers[_workerAddress].workerAddress == address(0)) {
            revert WorkerNotFound();
        }

        WorkerStatus oldStatus = workers[_workerAddress].status;
        workers[_workerAddress].status = _newStatus;

        emit WorkerStatusChanged(
            _workerAddress,
            oldStatus,
            _newStatus,
            block.timestamp
        );
    }

    /**
     * @dev Update total earned amount for a worker (called by PayrollContract)
     * @param _workerAddress Address of the worker
     * @param _amount Amount earned
     */
    function updateTotalEarned(address _workerAddress, uint256 _amount) external {
        if (workers[_workerAddress].workerAddress == address(0)) {
            revert WorkerNotFound();
        }
        workers[_workerAddress].totalEarned += _amount;

        emit TotalEarnedUpdated(_workerAddress, _amount, block.timestamp);
    }

    /**
     * @dev Set new KYC verifier (only owner)
     * @param _newVerifier New verifier address
     */
    function setKYCVerifier(address _newVerifier) external onlyOwner {
        if (_newVerifier == address(0)) revert InvalidAddress();
        address oldVerifier = kycVerifier;
        kycVerifier = _newVerifier;

        emit KYCVerifierChanged(oldVerifier, _newVerifier, block.timestamp);
    }

    /**
     * @dev Set company registry address (only owner)
     * @param _companyRegistry New company registry address
     */
    function setCompanyRegistry(address _companyRegistry) external onlyOwner {
        if (_companyRegistry == address(0)) revert InvalidAddress();
        address oldRegistry = companyRegistry;
        companyRegistry = _companyRegistry;

        emit CompanyRegistryChanged(oldRegistry, _companyRegistry, block.timestamp);
    }

    /**
     * @dev Get worker details
     * @param _workerAddress Address of the worker
     */
    function getWorker(address _workerAddress) external view returns (Worker memory) {
        if (workers[_workerAddress].workerAddress == address(0)) {
            revert WorkerNotFound();
        }
        return workers[_workerAddress];
    }

    /**
     * @dev Check if an address is a registered worker
     * @param _workerAddress Address to check
     */
    function isWorker(address _workerAddress) external view returns (bool) {
        return workers[_workerAddress].workerAddress != address(0);
    }

    /**
     * @dev Check if a worker is verified (Active status)
     * @param _workerAddress Address of the worker
     */
    function isVerifiedWorker(address _workerAddress) external view returns (bool) {
        return workers[_workerAddress].status == WorkerStatus.Active;
    }

    /**
     * @dev Get workers by employer
     * @param _employer Address of the employer
     */
    function getWorkersByEmployer(address _employer) external view returns (address[] memory) {
        uint256 length = workerAddresses.length();
        uint256 count = 0;

        // First pass: count matching workers
        for (uint256 i = 0; i < length; i++) {
            if (workers[workerAddresses.at(i)].employer == _employer) {
                count++;
            }
        }

        // Second pass: collect addresses
        address[] memory addresses = new address[](count);
        uint256 index = 0;

        for (uint256 i = 0; i < length; i++) {
            if (workers[workerAddresses.at(i)].employer == _employer) {
                addresses[index] = workerAddresses.at(i);
                index++;
            }
        }

        return addresses;
    }

    /**
     * @dev Get workers by status
     * @param _status Status to filter by
     */
    function getWorkersByStatus(WorkerStatus _status) external view returns (address[] memory) {
        uint256 length = workerAddresses.length();
        uint256 count = 0;

        // First pass: count matching workers
        for (uint256 i = 0; i < length; i++) {
            if (workers[workerAddresses.at(i)].status == _status) {
                count++;
            }
        }

        // Second pass: collect addresses
        address[] memory addresses = new address[](count);
        uint256 index = 0;

        for (uint256 i = 0; i < length; i++) {
            if (workers[workerAddresses.at(i)].status == _status) {
                addresses[index] = workerAddresses.at(i);
                index++;
            }
        }

        return addresses;
    }

    /**
     * @dev Get total number of registered workers
     */
    function getTotalWorkers() external view returns (uint256) {
        return workerAddresses.length();
    }

    /**
     * @dev Get all registered worker addresses
     */
    function getAllWorkerAddresses() external view returns (address[] memory) {
        uint256 length = workerAddresses.length();
        address[] memory addresses = new address[](length);

        for (uint256 i = 0; i < length; i++) {
            addresses[i] = workerAddresses.at(i);
        }

        return addresses;
    }

    /**
     * @dev Get paginated list of workers
     * @param _offset Starting index
     * @param _limit Number of workers to return
     */
    function getPaginatedWorkers(uint256 _offset, uint256 _limit) external view returns (Worker[] memory) {
        uint256 length = workerAddresses.length();
        if (_offset >= length) {
            return new Worker[](0);
        }

        uint256 end = _offset + _limit;
        if (end > length) {
            end = length;
        }

        Worker[] memory workerList = new Worker[](end - _offset);
        uint256 index = 0;

        for (uint256 i = _offset; i < end; i++) {
            workerList[index] = workers[workerAddresses.at(i)];
            index++;
        }

        return workerList;
    }
}
